import{_ as a,o as t,c as o,a3 as s}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"Tenant API v1 — Tasks","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant API v1 — Tasks | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/tenant-v1-tasks"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant API v1 — Tasks | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/tenant-v1-tasks"}]]},"headers":[],"relativePath":"api/tenant-v1-tasks.md","filePath":"api/tenant-v1-tasks.md","lastUpdated":1784364994000}'),d={name:"api/tenant-v1-tasks.md"};function c(i,e,n,r,l,p){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="tenant-api-v1-—-tasks" tabindex="-1">Tenant API v1 — Tasks <a class="header-anchor" href="#tenant-api-v1-—-tasks" aria-label="Permalink to &quot;Tenant API v1 — Tasks&quot;">​</a></h1><p>Base path: <code>/api/tenant/v1</code></p><p>Middleware: <code>auth:tenant-api</code>, <code>tenant.user</code>, <code>verified</code>, <code>module:tasks</code>, plus permission middleware / policies.</p><p>Assignee scoping: without <code>tasks.assign</code> (and not superadmin), list/board/stats only include tasks where <code>assigned_to</code> is the current user.</p><h2 id="stats-board" tabindex="-1">Stats &amp; board <a class="header-anchor" href="#stats-board" aria-label="Permalink to &quot;Stats &amp; board&quot;">​</a></h2><h3 id="get-tasks-stats" tabindex="-1">GET <code>/tasks/stats</code> <a class="header-anchor" href="#get-tasks-stats" aria-label="Permalink to &quot;GET `/tasks/stats`&quot;">​</a></h3><p>Same filters as list (minus pagination/sort). Payload includes:</p><p><code>total_tasks</code>, <code>my_tasks</code>, <code>due_today</code>, <code>due_this_week</code>, <code>overdue</code>, <code>completed_today</code>, <code>completion_rate</code>, <code>scope</code> (<code>org</code>|<code>mine</code>).</p><h3 id="get-tasks-board" tabindex="-1">GET <code>/tasks/board</code> <a class="header-anchor" href="#get-tasks-board" aria-label="Permalink to &quot;GET `/tasks/board`&quot;">​</a></h3><p>One column per status (<code>open</code>, <code>in_progress</code>, <code>waiting</code>, <code>completed</code>, <code>cancelled</code>): <code>status</code>, <code>task_count</code>, <code>tasks[]</code>. Honors the same filters as list.</p><h2 id="tasks-crud" tabindex="-1">Tasks CRUD <a class="header-anchor" href="#tasks-crud" aria-label="Permalink to &quot;Tasks CRUD&quot;">​</a></h2><h3 id="get-tasks" tabindex="-1">GET <code>/tasks</code> <a class="header-anchor" href="#get-tasks" aria-label="Permalink to &quot;GET `/tasks`&quot;">​</a></h3><p>Query: <code>search</code>, <code>status</code>, <code>priority</code>, <code>assigned_to</code> (<code>unassigned</code> or user id), <code>trashed</code>, <code>sort</code>, <code>direction</code>, <code>page</code>, <code>per_page</code>.</p><p>Status values: <code>open</code>, <code>in_progress</code>, <code>waiting</code>, <code>completed</code>, <code>cancelled</code>.<br> Priority values: <code>low</code>, <code>medium</code>, <code>high</code>, <code>urgent</code>.</p><h3 id="post-tasks" tabindex="-1">POST <code>/tasks</code> <a class="header-anchor" href="#post-tasks" aria-label="Permalink to &quot;POST `/tasks`&quot;">​</a></h3><p>Body: <code>title</code> (required), <code>description</code>, <code>status</code>, <code>priority</code>, <code>due_at</code>, <code>assigned_to</code>.</p><p>Initial <code>due_at</code> on create does not require <code>tasks.change_due_date</code>.</p><h3 id="get-tasks-id" tabindex="-1">GET <code>/tasks/{id}</code> <a class="header-anchor" href="#get-tasks-id" aria-label="Permalink to &quot;GET `/tasks/{id}`&quot;">​</a></h3><p>Includes assignee, creator, notes, activities.</p><h3 id="put-tasks-id" tabindex="-1">PUT <code>/tasks/{id}</code> <a class="header-anchor" href="#put-tasks-id" aria-label="Permalink to &quot;PUT `/tasks/{id}`&quot;">​</a></h3><p>Partial update of task fields (including <code>status</code> / <code>priority</code> / <code>assigned_to</code> / <code>due_at</code>).</p><p>Changing <code>due_at</code> after create requires <code>tasks.change_due_date</code> (403 otherwise).</p><h3 id="delete-tasks-id" tabindex="-1">DELETE <code>/tasks/{id}</code> <a class="header-anchor" href="#delete-tasks-id" aria-label="Permalink to &quot;DELETE `/tasks/{id}`&quot;">​</a></h3><p>Soft delete.</p><h2 id="actions" tabindex="-1">Actions <a class="header-anchor" href="#actions" aria-label="Permalink to &quot;Actions&quot;">​</a></h2><h3 id="post-tasks-id-assign" tabindex="-1">POST <code>/tasks/{id}/assign</code> <a class="header-anchor" href="#post-tasks-id-assign" aria-label="Permalink to &quot;POST `/tasks/{id}/assign`&quot;">​</a></h3><p><code>{ &quot;assigned_to&quot;: number|null }</code></p><h3 id="post-tasks-id-complete" tabindex="-1">POST <code>/tasks/{id}/complete</code> <a class="header-anchor" href="#post-tasks-id-complete" aria-label="Permalink to &quot;POST `/tasks/{id}/complete`&quot;">​</a></h3><p>Marks status <code>completed</code> and sets <code>completed_at</code>.</p><h3 id="post-tasks-id-reopen" tabindex="-1">POST <code>/tasks/{id}/reopen</code> <a class="header-anchor" href="#post-tasks-id-reopen" aria-label="Permalink to &quot;POST `/tasks/{id}/reopen`&quot;">​</a></h3><p>Clears completion and returns the task to a non-completed status (typically open/in-progress workflow in the UI).</p><h3 id="post-tasks-id-notes" tabindex="-1">POST <code>/tasks/{id}/notes</code> <a class="header-anchor" href="#post-tasks-id-notes" aria-label="Permalink to &quot;POST `/tasks/{id}/notes`&quot;">​</a></h3><p><code>{ &quot;body&quot;: string }</code> — comments in the UI.</p><h3 id="get-tasks-id-timeline" tabindex="-1">GET <code>/tasks/{id}/timeline</code> <a class="header-anchor" href="#get-tasks-id-timeline" aria-label="Permalink to &quot;GET `/tasks/{id}/timeline`&quot;">​</a></h3><p>Task activity timeline entries (History tab).</p>',35)])])}const u=a(d,[["render",c]]);export{k as __pageData,u as default};
